export const formatDate = (iso: string | null | undefined): string => {
  if (!iso) return '—';
  try {
    return new Date(iso).toLocaleDateString('vi-VN', {
      day: '2-digit', month: '2-digit', year: 'numeric',
    });
  } catch {
    return iso;
  }
};

export const formatCurrency = (value: number | null | undefined): string => {
  if (value == null) return '—';
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(value);
};

export const formatNumber = (value: number | null | undefined): string => {
  if (value == null) return '—';
  return new Intl.NumberFormat('vi-VN').format(value);
};

export const formatDateTimeLocal = (iso: string) =>
  iso ? new Date(iso).toLocaleString('vi-VN') : '';

const hasFraction = (n: number) => Math.abs(n % 1) > 1e-9;

function formatMoney(value: number | null | undefined): string {
  if (value == null) return '0';
  const n = Math.round(Number(value));
  if (!Number.isFinite(n)) return '0';
  return n.toLocaleString('de-DE', { maximumFractionDigits: 0 });
}

export function formatMoneyVnd(value: number | null | undefined): string {
  if (value == null) return '—';
  return `${formatMoney(value)} đ`;
}

export function formatQuantity(
  value: number | null | undefined,
  maxDecimals = 3,
): string {
  if (value == null) return '0';
  const n = Number(value);
  if (!Number.isFinite(n)) return '0';
  if (!hasFraction(n)) {
    return Math.round(n)
      .toLocaleString('vi-VN', { maximumFractionDigits: 0 })
      .replace(/\./g, ' ');
  }
  const formatted = n.toLocaleString('vi-VN', {
    minimumFractionDigits: 1,
    maximumFractionDigits: maxDecimals,
  });
  const commaIdx = formatted.lastIndexOf(',');
  if (commaIdx < 0) return formatted.replace(/\./g, ' ');
  return `${formatted.slice(0, commaIdx).replace(/\./g, ' ')},${formatted.slice(commaIdx + 1)}`;
}

